<!DOCTYPE html>
<html lang="es"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>Verificar acceso · Censo APP</title><link rel="stylesheet" href="<?= base_url('assets/css/app.css') ?>"><style>body{min-height:100vh;display:grid;place-items:center;background:#101826;margin:0;padding:20px}.verify{width:min(420px,100%);background:#fff;border-radius:8px;padding:28px}.code{font-size:1.4rem;letter-spacing:4px;text-align:center}.verify button{width:100%}</style></head><body><main class="verify"><h1>Verificar acceso</h1><p>Enviamos un codigo de seis digitos a <strong><?= esc($maskedEmail) ?></strong>.</p><?php if(session('error')): ?><div class="alert alert-error"><?= esc(session('error')) ?></div><?php endif; ?><form method="post" action="<?= base_url('login/verificar') ?>"><?= csrf_field() ?><label for="codigo">Codigo</label><input class="code" id="codigo" name="codigo" inputmode="numeric" pattern="[0-9]{6}" maxlength="6" autocomplete="one-time-code" required autofocus><button class="btn btn-primary" type="submit">Verificar</button></form><p><a href="<?= base_url('logout') ?>">Cancelar</a></p></main></body></html>
